const Component = () => {
  // Sample data
  const data = [
    { region: 'North America', revenue: 120 },
    { region: 'Europe', revenue: 95 },
    { region: 'Asia Pacific', revenue: 150 },
    { region: 'Latin America', revenue: 65 },
    { region: 'Middle East', revenue: 45 },
    { region: 'Africa', revenue: 30 },
  ];

  const option = {
    theme: 'carbon-light',
    title: {
      text: 'Regional Revenue Performance',
      left: 'center',
    },
    tooltip: {
      trigger: 'axis',
      axisPointer: {
        type: 'shadow',
      },
    },
    xAxis: {
      type: 'category',
      data: data.map(item => item.region),
    },
    yAxis: {
      type: 'value',
      name: 'Revenue (in millions)',
    },
    series: [
      {
        data: data.map(item => item.revenue),
        type: 'bar',
        itemStyle: {
          borderRadius: [8, 8, 0, 0],
        },
        label: {
          show: true,
          position: 'top',
        },
      },
    ],
  };

  return (
    <div>
      <ReactECharts option={option} style={{ height: '400px' }} theme="carbon-light" />
    </div>
  );
};
